import{Alerter}from"./index.min.js";class PostEditor{constructor(){this.alerter=new Alerter,this.postID=document.getElementById("content-container").dataset.postId,this.editButton=document.getElementById("edit-mode-button"),this.commentsBox=document.getElementById("comments-box"),this.infoBox=document.getElementById("info-box"),this.editorBox=document.getElementById("edit-box"),this.editButton.onclick=()=>{this.toggleEditMode()}}toggleEditMode(){this.commentsBox.style.display="none"==this.commentsBox.style.display?"block":"none",this.infoBox.style.display="none"==this.infoBox.style.display?"block":"none",this.editorBox.style.display="block"==this.editorBox.style.display?"none":"block",this.editButton.innerText="Edit Post"==this.editButton.innerText?"Exit Edit Mode":"Edit Post"}}export{PostEditor};